      /* <flatten type="Javascript"> */
function load$GridEmployeeInformationFamily$(g) {
  g.add_commandEvent(on$GridEmployeeInformationFamily$ExecuteCommand);
  g.add_onResponseComplete(on$GridEmployeeInformationFamily$ResponseComplete);
}
function dispose$GridEmployeeInformationFamily$(g) {
  try {g.remove_commandEvent(on$GridEmployeeInformationFamily$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridEmployeeInformationFamily$ResponseComplete);} catch (ex) {}
}
function on$GridEmployeeInformationFamily$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      g.setItemFieldValue('stt_rec_nv', e.type.Value, '');

      var r = g._activeRow, a = ['loai_so', 'ho_khau_so', 'dia_chi', 'ho_khau_tinh', 'ho_khau_quan', 'ho_khau_phuong'];
      g._getItem(r, g._getColumnOrder('chu_ho')).checked = false;
      setEmpty(g, r, a);
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      g.request(g, 'Retrieve', 'Retrieve', [], ['stt_rec']);
      break;
    default:
      break;
  }
}
function on$GridEmployeeInformationFamily$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Retrieve':
      var l0 = g._getColumnOrder('stt_rec_nv'), l1 = g._getColumnOrder('chu_ho'), first = true, c;
      var siNum = f.getItemValue('si_no'), siCode = f.getItemValue('ma_so_bhxh');
      for (var i = 0; i < result.length; i++) {
        var a  = result[i];
        var ins = true, row = g._rowCount;
        if (first && row > 0) if (g.blankMemvar(row)) {ins = false; first = false;}
        if a[1] == '' { insert$GridVoucherDetail$Items(g, ins, l0, 'stt_rec_nv, ho_ten, ma_qh, ngay_sinh, dien_thoai, gioi_tinh, cmnd_so', [a[1], a[2], a[3], a[4], a[9], a[10], a[11]]);}
        else {
          for (var r = 1; r <= g._rowCount; r++) {
            if (g._getItemValue(r, l0) == a[1]) {
              var o2 = g._getItem(r, l1);
              c = true;
              setSI(g, r, f, [{name:'ma_so_bhxh', value: siCode}, {name:'si_so', value: siNum}]);
              if (o2.checked) {
                var t = [{name:'dia_chi', value: a[5]}, {name:'ho_khau_tinh', value: a[6]}, {name:'ho_khau_quan', value: a[7]}, {name:'ho_khau_phuong', value: a[8]}, {name:'dien_thoai', value: a[9]}, {name:'gioi_tinh', value: a[10]}, {name:'cmnd_so', value: a[11]}, {name:'ma_tinh', value: a[12]}, {name:'ma_quan', value: a[13]}, {name:'ma_phuong', value: a[14]}];
                for (var k = 0; k < t.length; k++) {
                  var cl = g._getColumnOrder($func.trim(t[k].name));
                  g._setItemValue(r, cl, t[k].value);
                }
                break;
              }
            }
          }
          if (!c) { insert$GridVoucherDetail$Items(g, ins, l0, 'stt_rec_nv, ho_ten, ma_qh, ngay_sinh, gioi_tinh, cmnd_so, ma_tinh, ma_quan, ma_phuong, ma_so_bhxh, si_so', [a[1], a[2], a[3], a[4], a[10], a[11], a[12], a[13], a[14], siCode, siNum]); }
        }
      }
      break;
    case 'Employee':
      var t = [{name:'dia_chi', value: result[0].Value}, {name:'ho_khau_tinh', value: result[1].Value}, {name:'ho_khau_quan', value: result[2].Value}, {name:'ho_khau_phuong', value: result[3].Value}, {name:'dien_thoai', value: result[4].Value}, {name:'gioi_tinh', value: result[5].Value}];
      for (var i = 0; i < t.length; i++) {
        var cl = g._getColumnOrder($func.trim(t[i].name));
        g._setItemValue(g._activeRow, cl, t[i].value);
      }
      break;
    default:
      break;
  }
}
function insert$GridVoucherDetail$Items(g, ins, c, columns, v) {
  if (ins) g._appendRow(null, true);
  var r = g._rowCount;
  var o = g._getItem(r, c);
  o.row = r;
  var a = columns.split(',');
  for (var i = 0; i < a.length; i++) {
    var l = g._getColumnOrder($func.trim(a[i]));
    g._setItemValue(r, l, v[i]);
  }
}
function check$GridVoucherDetail$EmployeeID(g, c, v) {
  for (var r = 1; r <= g._rowCount; r++) {
    if (g._getItemValue(r, c) == v) return 0;
  }
  return 1;
}

function onChange$Province(o) {
  var g = o.grid, a = ['ma_quan', 'ma_phuong'];
  setEmpty(g, g._activeRow, a);
}

function onChange$District(o) {
  var g = o.grid, , a = ['ma_phuong'];
  setEmpty(g, g._activeRow, a);
}

function onChange$HeadOfAHousehold(o) {
  var v = o.checked, g = o.grid, r = g._activeRow, c = g._getColumnOrder('chu_ho'), a = ['loai_so', 'ho_khau_so', 'dia_chi', 'ho_khau_tinh', 'ho_khau_quan', 'ho_khau_phuong', 'dien_thoai'];
  if (!v) { setEmpty(g, r, a);}
  else {
    var k = g._getItem(r, g._getColumnOrder('stt_rec_nv')).value;
    if (k != '') { g.request(o, 'Employee', 'Employee', [['stt_rec', 'String', k]]); }
    for (var i = 1; i <= g._rowCount; i++) {
      if (i != r) {
        var o2 = g._getItem(i, c);
        if (o2.checked) {
          o2.checked = false;
          setEmpty(g, i, a);
          break;
        }
      }
    }
  }
}
function onChange$ProvinceCityHouse(o) {
  var g = o.grid, a = ['ho_khau_quan', 'ho_khau_phuong'];
  setEmpty(g, g._activeRow, a);
}
function onChange$DistrictHouse(o) {
  var g = o.grid, , a = ['ho_khau_phuong'];
  setEmpty(g, g._activeRow, a);
}

function setEmpty(g, r, a) {
  for (var i = 0; i < a.length; i++) {
    var l = g._getColumnOrder($func.trim(a[i]));
    g._setItemValue(r, l, '');
  }
}
function setSI(g, r, f, a) {
  for (var i = 0; i < a.length; i++) {
    var c = g._getColumnOrder(a[i].name);
    g._setItemValue(r, c, a[i].value);
  }
}
/* </flatten> */
